function freshPlayer():Player{return{x:W/2,y:540,hp:120,maxHp:120,energy:100,maxEnergy:100,speed:245,inv:0,dashCd:0,dashMax:1.05,weapon:0,coins:0}}
function circleRect(x:number,y:number,r:number,o:{x:number;y:number;w:number;h:number}){const cx=Math.max(o.x,Math.min(x,o.x+o.w)),cy=Math.max(o.y,Math.min(y,o.y+o.h));return Math.hypot(x-cx,y-cy)<r}
function blocked(x:number,y:number,r:number,obs=fallbackObstacles){return x-r<LEFT+18||x+r>RIGHT-18||y-r<TOP+18||y+r>BOTTOM-18||obs.some(o=>circleRect(x,y,r,o))}
function styleRooms(plans:PreparedRoom[],settings:CustomizationSettings,seed:string,history:string[]){const recent=[...history];return plans.map(plan=>{const choice=chooseMapStyle({mode:settings.mapStyleMode,selectedId:settings.selectedMapStyleId,unlockedIds:settings.unlockedMapStyleIds,recentIds:recent,templateId:plan.templateId,pacingRole:plan.pacingRole,seed:`${seed}:${plan.roomSequenceIndex}`});recent.push(choice.id);return applyRoomMapStyle(plan,choice)})}
