function debugProfile(kind:string){const samples=Array.from({length:6},(_,i):EncounterMetrics=>({room:i+1,durationMs:kind==="expert"?26000:kind==="deaths"?120000:65000,shotsFired:50,shotsHit:kind==="expert"||kind==="aim-survival"?46:kind==="beginner"?10:28,criticalHits:kind==="expert"?12:3,kills:kind==="deaths"?2:8,damageTaken:kind==="expert"?3:kind==="aim-survival"||kind==="deaths"?92:35,movementMs:kind==="beginner"?5000:30000,abilityUses:3,energySpent:70,reactionTimesMs:[kind==="expert"?180:620],killTimesMs:[kind==="expert"?900:4200],deaths:kind==="deaths"?1:0,completed:kind!=="deaths"}));return calculateProfile(samples)}
function assembleRoomAndResolveSpawn(g:Game){const template=getRoomTemplate(g.currentRoom.templateId);if(!template)return;g.obstacles=template.obstacles.map(o=>({...o}));const hazardCount=g.currentRoom.hazardSetId==="none"?0:g.currentRoom.hazardSetId==="slow_field"?1:2;g.hazards=template.hazardZones.slice(0,hazardCount).map(h=>({x:h.x,y:h.y,r:h.r,kind:g.currentRoom.hazardSetId as Hazard["kind"],phase:0,cool:0}));const occupied=[...g.mobs.map(m=>({x:m.x,y:m.y,radius:m.r,kind:"enemy" as const})),...g.drops.map(d=>({x:d.x,y:d.y,radius:10,kind:"pickup" as const}))],resolution=resolveRoomPlayerSpawn(template,occupied);if(!resolution.success)throw new Error(`No safe player spawn for ${template.id}`);applyResolvedPlayerSpawn(g.p,resolution);g.spawnResolution=resolution;g.reservedSpawnZone=reservedSpawnBounds(resolution);if(process.env.NODE_ENV!=="production"&&resolution.fallbackUsed)console.warn("Player spawn fallback",{room:template.id,requested:resolution.requestedPosition,resolved:resolution.resolvedPosition,reasons:resolution.invalidReasons})}

